  // errors

  error MsgSenderIsNotTheController();

  error ExpectedLocked();

  // modifiers

  modifier whenLocked() {
    _requireLocked();

    _;
  }

  modifier onlyOwnerWhenLocked() {
    if (_locked) {
      _checkOwner();
    }

    _;
  }

  modifier onlyController() {
    _checkController();

    _;
  }

  // deployment

  constructor() TokenImpl() {
    //
  }

  function initialize(
    address gateway,
    address owner,
    string calldata name_,
    string calldata symbol_,
    address controller,
    bool locked_
  ) external {
    _initialize(gateway);

    _setOwner(owner, false);

    _name = name_;
    _symbol = symbol_;

    _controller = controller;
    _locked = locked_;
  }

  // public getters

  function name() public view virtual returns (string memory) {
    return _name;
  }

  function symbol() public view virtual returns (string memory) {
    return _symbol;
  }

  // external getters

  function getController() external view returns (address) {
    return _controller;
  }

  function locked() external view returns (bool) {
    return _locked;
  }

  // external setters

  function unlock() external onlyOwner whenLocked {
    _locked = false;

    emit Unlocked();

    _notifyTokenRegistry(0x10, new bytes(0));
  }

  // private getters

  function _requireLocked() private view {
    if (!_locked) {
      revert ExpectedLocked();
    }
  }

  function _checkController() private view {
    address msgSender = _msgSender();

    if (msgSender != _controller) {
      if (_locked) {
        _checkOwner(msgSender);
      } else {
        revert MsgSenderIsNotTheController();
      }
    }
  }
}

